mapper.select:
SELECT data_hash FROM financehub.overseas_stock_daily_trading
WHERE data_hash IN

    #{hash}

SELECT id, bass_dt AS bassDt, isu_cd AS isuCd, isu_nm AS isuNm, excd,
       curr, cls_prc AS clsPrc, opn_prc AS opnPrc, hgst_prc AS hgstPrc,
       lwst_prc AS lwstPrc, acc_trd_vol AS accTrdVol, fluc_rt AS flucRt, data_hash AS dataHash
FROM financehub.overseas_stock_daily_trading
WHERE isu_cd = #{isuCd}
  AND excd = #{excd}
ORDER BY bass_dt DESC
LIMIT #{limit}

SELECT id, bass_dt AS bassDt, isu_cd AS isuCd, isu_nm AS isuNm, excd,
       curr, cls_prc AS clsPrc, opn_prc AS opnPrc, hgst_prc AS hgstPrc,
       lwst_prc AS lwstPrc, acc_trd_vol AS accTrdVol, fluc_rt AS flucRt, data_hash AS dataHash
FROM financehub.overseas_stock_daily_trading
WHERE isu_cd = #{isuCd}
  AND excd = #{excd}
  AND bass_dt >= #{startDate}
  AND bass_dt <= #{endDate}
ORDER BY bass_dt DESC
